(() => {
  const ASSISTANT_URL = 'https://cdn.jsdelivr.net/gh/yuzi83/st-yuzi-phone@main/dist/assistant/yuzi-phone.assistant.js';
  const SCRIPT_ATTR = 'data-yuzi-phone-assistant-loader';
  const SCRIPT_MARK = 'main';
  const logPrefix = '[YuziPhoneAssistantLoader]';

  async function safeInit() {
    const api = window.YuziPhoneAssistant;
    if (!api || typeof api.init !== 'function') throw new Error('window.YuziPhoneAssistant.init 不可用');
    const ok = await api.init();
    if (!ok) throw new Error('YuziPhoneAssistant.init() 返回 false');
    return true;
  }

  function getExistingScript() {
    return document.querySelector(`script[${SCRIPT_ATTR}=\"${SCRIPT_MARK}\"]`);
  }

  function loadScriptOnce() {
    return new Promise((resolve, reject) => {
      const existing = getExistingScript();
      if (existing) {
        if (existing.dataset.loaded === '1') return resolve();
        existing.addEventListener('load', () => resolve(), { once: true });
        existing.addEventListener('error', () => reject(new Error('已有 assistant 脚本加载失败')), { once: true });
        return;
      }

      const script = document.createElement('script');
      script.type = 'module';
      script.src = ASSISTANT_URL;
      script.async = true;
      script.setAttribute(SCRIPT_ATTR, SCRIPT_MARK);
      script.addEventListener('load', () => { script.dataset.loaded = '1'; resolve(); }, { once: true });
      script.addEventListener('error', () => reject(new Error(`加载失败: ${ASSISTANT_URL}`)), { once: true });
      document.head.appendChild(script);
    });
  }

  (async () => {
    try {
      if (window.YuziPhoneAssistant && typeof window.YuziPhoneAssistant.init === 'function') {
        await safeInit();
        console.info(`${logPrefix} 已复用现有实例并初始化`);
        return;
      }
      await loadScriptOnce();
      await safeInit();
      console.info(`${logPrefix} 加载并初始化成功`);
    } catch (error) {
      console.error(`${logPrefix} 启动失败`, error);
    }
  })();
})();
